import hashlib
import hmac

def encrypt_credit_card(number):
    # Use a fast encryption method such as SHA-256
    encrypted = hashlib.sha256(str(number).encode()).hexdigest()
    
    # Add a HMAC to ensure the integrity of the data
    hmac_key = "your_secret_key"
    hmac_encrypted = hmac.new(hmac_key, encrypted.encode(), hashlib.sha256).hexdigest()
    
    return hmac_encrypted